import React from 'react';

export default function MetricCard({ title, value, percentage, trends = [] }) {
  const isPositive = percentage >= 0;

  // Generate SVG Sparkline coordinates path
  const width = 100;
  const height = 30;
  const padding = 2;
  const minVal = Math.min(...trends);
  const maxVal = Math.max(...trends);
  const range = maxVal - minVal || 1;

  const points = trends.map((val, idx) => {
    const x = (idx / (trends.length - 1)) * (width - padding * 2) + padding;
    const y = height - ((val - minVal) / range) * (height - padding * 2) - padding;
    return `${x},${y}`;
  }).join(' ');

  return (
    <div className="w-72 border border-gray-250 rounded-2xl p-5 bg-white shadow-xs font-sans">
      <div className="flex justify-between items-start">
        <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">{title}</span>
        <svg className="w-4 h-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
      </div>

      <div className="flex items-baseline gap-2 mt-2">
        <span className="text-2xl font-bold text-gray-800">{value}</span>
        <span className={`text-xs font-semibold px-2 py-0.5 rounded-full flex items-center gap-0.5 ${
          isPositive ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
        }`}>
          {isPositive ? '↑' : '↓'} {Math.abs(percentage)}%
        </span>
      </div>

      {/* SVG Sparkline */}
      {trends.length > 1 && (
        <div className="mt-4 pt-2 flex items-center justify-between border-t border-gray-50">
          <span className="text-[10px] text-gray-400 font-medium">Last 7 days trend</span>
          <svg width={width} height={height} className="overflow-visible">
            <polyline
              fill="none"
              stroke={isPositive ? "#22c55e" : "#ef4444"}
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              points={points}
            />
          </svg>
        </div>
      )}
    </div>
  );
}
